  app_id: 'test_app_id',
  x_api_key: import.meta.env.VITE_PREMBLY_API_KEY,
  environment: 'test',
  sandbox_url: 'https://api.prembly.com',
  config_id: 'test_config_id',
  user_ref: 'user_' + Math.random().toString(36).substring(2, 9),
});

document.getElementById('launch-widget').addEventListener('click', () => {
